def predict(triples: list[Triple]) -> str:
    """Generate a natural language sentence from a list of triples."""
    if not triples:
        return ""

    def clean_subject(subject: str) -> str:
        """Remove '(comicsCharacter)' suffix from subject names."""
        return subject.replace(" (comicsCharacter)", "").replace("(comicsCharacter)", "")

    def clean_object(obj: str) -> str:
        """Remove surrounding quotes from object values."""
        if obj and ((obj.startswith('"') and obj.endswith('"')) or (obj.startswith("'") and obj.endswith("'"))):
            return obj[1:-1]
        return obj

    # Group triples by subject for complex sentence building
    subject_triples = {}
    for t in triples:
        subject = clean_subject(t.subject)
        if subject not in subject_triples:
            subject_triples[subject] = []
        subject_triples[subject].append((t.predicate, clean_object(t.object)))

    # Mapping predicates to phrase generators with better grammar
    def alt_name(s, o): return f"also known as {o}"
    def creator(s, o): return f"was created by {o}"
    def full_name(s, o): return f"whose full name is {o}"
    def founded_by(s, o): return f"was founded by {o}"
    def key_person(s, o): return f"{o} is a key person"
    def city(s, o): return f"located in {o}"
    def product(s, o): return f"produces {o}"
    def last_aired(s, o): return f"last aired on {o}"
    def starring(s, o): return f"stars {o}"
    def first_appearance(s, o): return f"first appeared in the film {o}"
    def voice(s, o): return f"voiced by {o}"
    def distributor(s, o): return f"distributed by {o}"
    def birth_place(s, o): return f"born in {o}"
    def nationality(s, o):
        # Handle nationality more naturally
        o_lower = o.lower()
        if o_lower == "americans" or o_lower == "united states":
            return "American"
        elif o_lower == "canadians":
            return "Canadian"
        elif o_lower == "british":
            return "British"
        elif o.endswith("s") and o not in ["US", "UK"]:
            return o[:-1]
        else:
            return o
    def award(s, o): return f"received the {o}"
    def broadcasted_by(s, o): return f"broadcasted by {o}"
    def first_aired(s, o): return f"first aired on {o}"
    def series(s, o): return f"part of the series {o}"
    def child(s, o): return f"has a child named {o}"

    phrase_funcs = {
        "alternativeName": alt_name,
        "creator": creator,
        "fullName": full_name,
        "foundedBy": founded_by,
        "keyPerson": key_person,
        "city": city,
        "product": product,
        "lastAired": last_aired,
        "starring": starring,
        "firstAppearanceInFilm": first_appearance,
        "voice": voice,
        "distributor": distributor,
        "birthPlace": birth_place,
        "nationality": nationality,
        "award": award,
        "broadcastedBy": broadcasted_by,
        "firstAired": first_aired,
        "series": series,
        "child": child,
    }

    # Build a single complex sentence from all triples by finding entity relationships
    all_clauses = []
    seen_predicates = set()
    subjects = list(subject_triples.keys())

    # Find the main subject (first subject in the list or most triples)
    main_subject = max(subject_triples.keys(), key=lambda s: len(subject_triples[s])) if subjects else ""

    # Track which subjects have been processed
    processed_subjects = set()

    def build_sentence_for_subject(subject, subject_trips, is_main=False):
        """Build a sentence fragment for a subject with its triples."""
        if subject in processed_subjects:
            return None

        # Sort triples by priority (more important info first)
        priority = ["creator", "fullName", "alternativeName", "nationality", "birthPlace", "award", "child", "starring", "firstAired", "lastAired", "broadcastedBy", "city", "product", "distributor", "series", "firstAppearanceInFilm", "voice", "foundedBy", "keyPerson", "product"]

        # Create a priority map for easier lookup
        priority_map = {p: i for i, p in enumerate(priority)}
        sorted_trips = sorted(subject_trips, key=lambda t: priority_map.get(t[0], len(priority)))

        # Deduplicate predicates
        unique_trips = []
        seen_pred_for_subject = set()
        for pred, obj in sorted_trips:
            if pred not in seen_pred_for_subject and pred not in seen_predicates:
                unique_trips.append((pred, obj))
                seen_pred_for_subject.add(pred)
                seen_predicates.add(pred)

        if not unique_trips:
            return None

        # Build the sentence fragment
        fragments = []

        for i, (pred, obj) in enumerate(unique_trips):
            func = phrase_funcs.get(pred)
            if func:
                if i == 0:
                    # First predicate - main clause
                    if pred == "nationality":
                        fragments.append(f"is {func(subject, obj)}")
                    elif is_main:
                        fragments.append(f"{func(subject, obj)}")
                    else:
                        fragments.append(f"which {func(subject, obj)}")
                else:
                    # Subsequent predicates - relative clauses
                    fragments.append(f", {func(subject, obj)}")
            else:
                if i == 0:
                    fragments.append(f"{pred} {obj}")
                else:
                    fragments.append(f", {pred} {obj}")

        processed_subjects.add(subject)

        if is_main:
            return f"{subject} {''.join(fragments)}"
        else:
            return f"{subject} {''.join(fragments)}"

    # Build main sentence
    main_sentence = build_sentence_for_subject(main_subject, subject_triples.get(main_subject, []), is_main=True)

    if not main_sentence:
        # Fallback: just use first subject
        first_subject = subjects[0] if subjects else ""
        main_sentence = build_sentence_for_subject(first_subject, subject_triples.get(first_subject, []), is_main=True)

    # Handle related subjects (objects that are subjects in other triples)
    related_sentences = []
    for subject in subjects:
        if subject not in processed_subjects and subject != main_subject:
            related_sentence = build_sentence_for_subject(subject, subject_triples.get(subject, []), is_main=False)
            if related_sentence:
                related_sentences.append(related_sentence)

    # Combine into one complex sentence
    def clean_spaces(text):
        while "  " in text:
            text = text.replace("  ", " ")
        return text.strip()

    if related_sentences:
        # Connect related subjects with relative clauses
        result = main_sentence
        for related in related_sentences:
            # Find common entity to connect
            result += f", and {related}"
    else:
        result = main_sentence

    result = clean_spaces(result)
    if not result.endswith("."):
        result += "."
    return result

